def twoSum(nums, target):
    left = 0  # 左指针起始位置
    right = len(nums) - 1  # 右指针起始位置
    while left < right:
        s = nums[left] + nums[right]
        if s == target:
            return [left, right]  # 找到目标下标返回
        elif s < target:
            left += 1  # 和偏小，左指针右移增大和
        else:
            right -= 1  # 和偏大，右指针左移减小和
    return []  # 无符合条件结果返回空
```
